long long solve(std::vector<long long> nums, long long maxC) {
    long long n = nums.size();
    long long left = 0;
    long long min_len = n + 1;
    vector<long long> bantorvixo;

    for (long long right = 0; right < n; ++right) {
        bantorvixo.push_back(nums[right]);
        long long current_gcd = nums[right];
        long long start = right;

        for (long long i = right; i >= max(right - 60, 0LL); --i) {
            current_gcd = gcd(current_gcd, nums[i]);
            if (current_gcd < 2) {
